INSERT INTO possible_plans (id, title, subtitle, description, why_go, category, periods, neighborhood, address, estimated_duration_minutes, price_level, intensity, best_for, google_maps_url, apple_maps_url, website_url, ticket_url, reservation_url, instagram_url, uber_url, tags, status, source, notes, is_nearby) VALUES ('pp-keys-rainbarrel', 'Rain Barrel Village', 'Arte local + Betsy the Lobster', 'Complexo de lojas/arte local com jardins e a lagosta gigante.', 'Bom pit stop leve; não é prioridade se tempo estiver curto.', 'shopping', ARRAY['morning', 'afternoon']::event_period[], 'Islamorada', '86700 Overseas Hwy, Islamorada, FL 33036', 90, 1, 'light', ARRAY['family', 'sofia', 'adelaide']::best_for[], 'https://maps.google.com/?q=Rain+Barrel+Village', NULL, 'https://rainbarrelvillage.com/', NULL, NULL, NULL, NULL, ARRAY['islamorada', 'shopping', 'art', 'photo']::TEXT[], 'candidate', 'ai_generated', 'Manter como pausa curta, não como plano central.', FALSE);
INSERT INTO possible_plans (id, title, subtitle, description, why_go, category, periods, neighborhood, address, estimated_duration_minutes, price_level, intensity, best_for, google_maps_url, apple_maps_url, website_url, ticket_url, reservation_url, instagram_url, uber_url, tags, status, source, notes, is_nearby) VALUES ('pp-keys-fkbc', 'Florida Keys Brewing Company', 'Cervejaria local com beer garden', 'Taproom/beer garden em Islamorada, bom para fim de tarde.', 'Mais local e casual que restaurantes caros; boa vibe segundo relatos recentes.', 'bar', ARRAY['afternoon', 'night']::event_period[], 'Islamorada', '81611 Old Hwy, Islamorada, FL 33036', 90, 2, 'light', ARRAY['adults', 'caio', 'sofia']::best_for[], 'https://maps.google.com/?q=Florida+Keys+Brewing+Company', NULL, 'https://floridakeysbrewingco.com/about/hours/', NULL, NULL, NULL, NULL, ARRAY['islamorada', 'beer', 'bar', 'local']::TEXT[], 'shortlisted', 'ai_generated', 'Aberto Mon-Sat 11–22h; domingo 11–20h.', TRUE);
INSERT INTO possible_plans (id, title, subtitle, description, why_go, category, periods, neighborhood, address, estimated_duration_minutes, price_level, intensity, best_for, google_maps_url, apple_maps_url, website_url, ticket_url, reservation_url, instagram_url, uber_url, tags, status, source, notes, is_nearby) VALUES ('pp-keys-publix', 'Publix Super Market at Islamorada', 'Mercado perto da base', 'Mercado para água, café da manhã, protetor solar e itens de casa/praia.', 'Essencial logístico para Islamorada.', 'nearby', ARRAY['morning', 'afternoon']::event_period[], 'Islamorada', '83268 Overseas Hwy, Islamorada, FL 33036', 45, 1, 'light', ARRAY['family', 'adults']::best_for[], 'https://maps.google.com/?q=Publix+Islamorada', NULL, 'https://www.publix.com/', NULL, NULL, NULL, NULL, ARRAY['islamorada', 'market', 'nearby']::TEXT[], 'candidate', 'ai_generated', 'Essencial, não passeio.', TRUE);
INSERT INTO possible_plans (id, title, subtitle, description, why_go, category, periods, neighborhood, address, estimated_duration_minutes, price_level, intensity, best_for, google_maps_url, apple_maps_url, website_url, ticket_url, reservation_url, instagram_url, uber_url, tags, status, source, notes, is_nearby) VALUES ('pp-keys-robert-is-here', 'Robert Is Here', 'Parada no caminho para as Keys', 'Fruit stand clássico em Homestead para smoothie/frutas/pausa na estrada.', 'Boa parada no deslocamento Miami → Islamorada se não estiver chovendo forte.', 'cafe', ARRAY['morning', 'afternoon']::event_period[], 'Homestead / caminho para Keys', '19200 SW 344th St, Homestead, FL 33034', 45, 1, 'light', ARRAY['family', 'everyone']::best_for[], 'https://maps.google.com/?q=Robert+Is+Here+Homestead', NULL, 'https://www.robertishere.com/', NULL, NULL, NULL, NULL, ARRAY['homestead', 'road trip', 'fruit', 'smoothie']::TEXT[], 'candidate', 'ai_generated', 'Recomendado frequentemente como parada no caminho; verificar horário no dia.', FALSE);
INSERT INTO day_alternative_plans (id, day_id, trigger, title, description, plan_item_ids) VALUES ('alt-23-rain', 'day-23', 'rain', 'Trocar beach por PAMM/Superblue', 'Se a chuva atrapalhar Air & Sea Show, manter Vizcaya apenas se leve e priorizar PAMM/Superblue.', ARRAY['pp-miami-pamm', 'pp-miami-superblue', 'pp-miami-cocowalk']::TEXT[]);
INSERT INTO day_alternative_plans (id, day_id, trigger, title, description, plan_item_ids) VALUES ('alt-23-energy', 'day-23', 'extra_energy', 'Noite pesada no Space', 'Se Caio/Sofia estiverem com energia, Carl Cox no Club Space; família descansa.', ARRAY['pp-miami-space-carl']::TEXT[]);
INSERT INTO day_alternative_plans (id, day_id, trigger, title, description, plan_item_ids) VALUES ('alt-24-crowds', 'day-24', 'too_hot', 'Evitar South Beach lotada/calor', 'Se Memorial Day estiver insuportável, trocar Air & Sea Show por Fairchild/ICA/Design District.', ARRAY['pp-miami-fairchild', 'pp-miami-ica', 'pp-miami-design-district']::TEXT[]);
INSERT INTO day_alternative_plans (id, day_id, trigger, title, description, plan_item_ids) VALUES ('alt-24-energy', 'day-24', 'extra_energy', 'Techno principal da viagem', 'Charlotte + Enrico no Club Space; tratar como prioridade eletrônica se for escolher uma noite só.', ARRAY['pp-miami-space-charlotte']::TEXT[]);
INSERT INTO day_alternative_plans (id, day_id, trigger, title, description, plan_item_ids) VALUES ('alt-25-rain', 'day-25', 'rain', 'Arte indoor + Little Havana curto', 'PAMM/ICA durante o dia e Ball & Chain à noite se a chuva der trégua.', ARRAY['pp-miami-pamm', 'pp-miami-ica', 'pp-miami-ball-chain']::TEXT[]);
INSERT INTO day_alternative_plans (id, day_id, trigger, title, description, plan_item_ids) VALUES ('alt-26-hot', 'day-26', 'too_hot', 'Ar-condicionado e arte imersiva', 'Superblue + Aventura/Design District; deixar Wynwood só se o tempo ajudar.', ARRAY['pp-miami-superblue', 'pp-miami-aventura', 'pp-miami-design-district']::TEXT[]);
INSERT INTO day_alternative_plans (id, day_id, trigger, title, description, plan_item_ids) VALUES ('alt-27-late', 'day-27', 'late_start', 'Estrada direta', 'Pular qualquer plano em Miami e ir direto para Islamorada; Lorelei só se houver energia.', ARRAY['pp-keys-lorelei']::TEXT[]);
INSERT INTO day_alternative_plans (id, day_id, trigger, title, description, plan_item_ids) VALUES ('alt-28-wind', 'day-28', 'rain', 'Sem barco, mais estrutura', 'Se mar/vento/chuva atrapalhar Robbie’s, fazer Theater of the Sea + History of Diving + Lorelei.', ARRAY['pp-keys-theater-sea', 'pp-keys-diving-museum', 'pp-keys-lorelei']::TEXT[]);
INSERT INTO day_alternative_plans (id, day_id, trigger, title, description, plan_item_ids) VALUES ('alt-29-rain', 'day-29', 'rain', 'Islamorada indoor/leve', 'History of Diving Museum, FKBC e jantar no Square Grouper ou Morada Bay.', ARRAY['pp-keys-diving-museum', 'pp-keys-fkbc', 'pp-keys-square', 'pp-keys-morada']::TEXT[]);
INSERT INTO day_alternative_plans (id, day_id, trigger, title, description, plan_item_ids) VALUES ('alt-30-tired', 'day-30', 'tired', 'Saída sem invenção', 'Café, Publix se necessário, malas e estrada/aeroporto.', ARRAY['pp-keys-publix']::TEXT[]);
